import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface GPXPoint {
  lat: number;
  lng: number;
  ele?: number;
  time?: Date;
}

export interface GPXTrack {
  id: string;
  name: string;
  points: GPXPoint[];
  color: string;
  distance: number; // in kilometers
  visible: boolean;
}

export enum MapLayer {
  OSM = 'OpenStreetMap',
  TOPOLOGY = 'OpenTopoMap',
  CYCLOSM = 'CyclOSM',
  SATELLITE = 'Satellite (Esri)'
}

export interface MapLayerConfig {
  id: MapLayer;
  url: string;
  attribution: string;
}

export const MAP_LAYERS: Record<MapLayer, MapLayerConfig> = {
  [MapLayer.OSM]: {
    id: MapLayer.OSM,
    url: 'https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png',
    attribution: '&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors'
  },
  [MapLayer.TOPOLOGY]: {
    id: MapLayer.TOPOLOGY,
    url: 'https://{s}.tile.opentopomap.org/{z}/{x}/{y}.png',
    attribution: 'Map data: &copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors, <a href="http://viewfinderpanoramas.org">SRTM</a> | Map style: &copy; <a href="https://opentopomap.org">OpenTopoMap</a> (<a href="https://creativecommons.org/licenses/by-sa/3.0/">CC-BY-SA</a>)'
  },
  [MapLayer.CYCLOSM]: {
    id: MapLayer.CYCLOSM,
    url: 'https://{s}.tile-cyclosm.openstreetmap.fr/cyclosm/{z}/{x}/{y}.png',
    attribution: '<a href="https://github.com/cyclosm/cyclosm-cartocss-style/releases" title="CyclOSM - Open Bicycle render">CyclOSM</a> | Map data: &copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors'
  },
  [MapLayer.SATELLITE]: {
    id: MapLayer.SATELLITE,
    url: 'https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}',
    attribution: 'Tiles &copy; Esri &mdash; Source: Esri, i-cubed, USDA, USGS, AEX, GeoEye, Getmapping, Aerogrid, IGN, IGP, UPR-EGP, and the GIS User Community'
  }
};

import { GPXPoint, GPXTrack } from '../types';

/**
 * Basic Haversine distance calculation in kilometers
 */
export const calculateDistance = (p1: GPXPoint, p2: GPXPoint): number => {
  const R = 6371; // Earth's radius in km
  const dLat = (p2.lat - p1.lat) * Math.PI / 180;
  const dLng = (p2.lng - p1.lng) * Math.PI / 180;
  const a = 
    Math.sin(dLat / 2) * Math.sin(dLat / 2) +
    Math.cos(p1.lat * Math.PI / 180) * Math.cos(p2.lat * Math.PI / 180) * 
    Math.sin(dLng / 2) * Math.sin(dLng / 2);
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
  return R * c;
};

export const calculateTotalDistance = (points: GPXPoint[]): number => {
  let total = 0;
  for (let i = 0; i < points.length - 1; i++) {
    total += calculateDistance(points[i], points[i + 1]);
  }
  return total;
};

export const parseGPX = (xmlString: string, fileName: string): GPXTrack | null => {
  try {
    const parser = new DOMParser();
    const xml = parser.parseFromString(xmlString, "text/xml");
    const trkpts = xml.querySelectorAll("trkpt");

    if (trkpts.length === 0) return null;

    const points: GPXPoint[] = Array.from(trkpts).map((pt) => {
      const lat = parseFloat(pt.getAttribute("lat") || "0");
      const lng = parseFloat(pt.getAttribute("lon") || "0");
      const ele = pt.querySelector("ele") ? parseFloat(pt.querySelector("ele")?.textContent || "0") : undefined;
      const timeStr = pt.querySelector("time")?.textContent;
      const time = timeStr ? new Date(timeStr) : undefined;
      return { lat, lng, ele, time };
    });

    const name = xml.querySelector("name")?.textContent || fileName || "Unbenannter Track";

    return {
      id: crypto.randomUUID(),
      name,
      points,
      color: `#${Math.floor(Math.random()*16777215).toString(16)}`,
      distance: calculateTotalDistance(points),
      visible: true
    };
  } catch (error) {
    console.error("Error parsing GPX:", error);
    return null;
  }
};

export const mergeTracks = (tracks: GPXTrack[]): GPXTrack => {
  const combinedPoints: GPXPoint[] = tracks.flatMap(t => t.points);
  const names = tracks.map(t => t.name).join(" + ");

  return {
    id: crypto.randomUUID(),
    name: `Verbunden: ${names.substring(0, 30)}${names.length > 30 ? '...' : ''}`,
    points: combinedPoints,
    color: "#ff0000",
    distance: calculateTotalDistance(combinedPoints),
    visible: true
  };
};

import React, { useEffect, useState } from 'react';
import { MapContainer, TileLayer, Polyline, useMapEvents, useMap, LayersControl, Marker, Popup } from 'react-leaflet';
import L from 'leaflet';
import { GPXTrack, MapLayer, MAP_LAYERS, GPXPoint } from '../types';
import { calculateDistance } from '../utils/gpxUtils';

// Fix for default marker icons in Leaflet + React
// @ts-ignore
delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon-2x.png',
  iconUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon.png',
  shadowUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-shadow.png',
});

interface MapProps {
  tracks: GPXTrack[];
  activeLayer: MapLayer;
  measureMode: boolean;
  onMeasureResult: (dist: number | null) => void;
}

const ZoomToTracks = ({ tracks }: { tracks: GPXTrack[] }) => {
  const map = useMap();
  useEffect(() => {
    const visibleTracks = tracks.filter(t => t.visible);
    if (visibleTracks.length > 0) {
      const bounds = L.latLngBounds(visibleTracks[0].points.map(p => [p.lat, p.lng]));
      visibleTracks.forEach(t => {
        t.points.forEach(p => bounds.extend([p.lat, p.lng]));
      });
      map.fitBounds(bounds, { padding: [50, 50] });
    }
  }, [tracks, map]);
  return null;
};

const MeasurementTool = ({ active, onResult }: { active: boolean, onResult: (d: number | null) => void }) => {
  const [points, setPoints] = useState<L.LatLng[]>([]);

  useMapEvents({
    click(e) {
      if (!active) return;

      const newPoints = [...points, e.latlng];
      if (newPoints.length > 2) {
        setPoints([e.latlng]);
        onResult(null);
      } else {
        setPoints(newPoints);
        if (newPoints.length === 2) {
          const d = calculateDistance(
            { lat: newPoints[0].lat, lng: newPoints[0].lng },
            { lat: newPoints[1].lat, lng: newPoints[1].lng }
          );
          onResult(d);
        }
      }
    },
  });

  if (!active || points.length === 0) return null;

  return (
    <>
      {points.map((p, i) => (
        <Marker key={i} position={p} icon={new L.DivIcon({
          className: 'custom-div-icon',
          html: `<div class="bg-blue-600 w-3 h-3 rounded-full border-2 border-white"></div>`,
          iconSize: [12, 12],
          iconAnchor: [6, 6]
        })} />
      ))}
      {points.length === 2 && (
        <Polyline positions={points} color="blue" dashArray="5, 10" />
      )}
    </>
  );
};

const Map: React.FC<MapProps> = ({ tracks, activeLayer, measureMode, onMeasureResult }) => {
  const layer = MAP_LAYERS[activeLayer];

  return (
    <div className="w-full h-full relative">
      <MapContainer 
        center={[51.1657, 10.4515]} 
        zoom={6} 
        scrollWheelZoom={true}
        className="z-0"
      >
        <TileLayer
          attribution={layer.attribution}
          url={layer.url}
        />

        {tracks.filter(t => t.visible).map(track => (
          <Polyline 
            key={track.id} 
            positions={track.points.map(p => [p.lat, p.lng])}
            color={track.color}
            weight={4}
            opacity={0.8}
          >
            <Popup>
                <div className="font-bold">{track.name}</div>
                <div>Distanz: {track.distance.toFixed(2)} km</div>
                <div>Punkte: {track.points.length}</div>
            </Popup>
          </Polyline>
        ))}

        <ZoomToTracks tracks={tracks} />
        <MeasurementTool active={measureMode} onResult={onMeasureResult} />
      </MapContainer>
    </div>
  );
};

export default Map;

