import React, { useState, useCallback, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Map from './components/Map';
import ElevationProfile from './components/ElevationProfile';
import { GPXTrack, MapLayer } from './types';
import { parseGPX, mergeTracks } from './utils/gpxUtils';
import { arrayMove } from '@dnd-kit/sortable';

const App: React.FC = () => {
  const [tracks, setTracks] = useState<GPXTrack[]>([]);
  const [history, setHistory] = useState<GPXTrack[][]>([]);
  const [activeLayer, setActiveLayer] = useState<MapLayer>(MapLayer.OSM);
  const [measureMode, setMeasureMode] = useState(false);
  const [measureResult, setMeasureResult] = useState<number | null>(null);
  const [markedTrackId, setMarkedTrackId] = useState<string | null>(null);

  // Auto-select first track if none is selected and tracks exist
  useEffect(() => {
    if (tracks.length > 0 && !markedTrackId) {
      setMarkedTrackId(tracks[0].id);
    } else if (tracks.length === 0) {
      setMarkedTrackId(null);
    }
  }, [tracks, markedTrackId]);

  const saveToHistory = useCallback(() => {
    setHistory(prev => [...prev, [...tracks]].slice(-10));
  }, [tracks]);

  const handleUndo = useCallback(() => {
    if (history.length === 0) return;
    const previousState = history[history.length - 1];
    setTracks(previousState);
    setHistory(prev => prev.slice(0, -1));
  }, [history]);

  const handleFileUpload = useCallback(async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files) return;

    const newTracks: GPXTrack[] = [];
    for (let i = 0; i < files.length; i++) {
      const file = files[i];
      const text = await file.text();
      const parsed = parseGPX(text, file.name);
      if (parsed) {
        newTracks.push(parsed);
      }
    }

    if (newTracks.length > 0) {
      saveToHistory();
      setTracks(prev => [...prev, ...newTracks]);
    }
    e.target.value = '';
  }, [saveToHistory]);

  const toggleVisibility = useCallback((id: string) => {
    setTracks(prev => prev.map(t => t.id === id ? { ...t, visible: !t.visible } : t));
  }, []);

  const removeTrack = useCallback((id: string) => {
    saveToHistory();
    setTracks(prev => prev.filter(t => t.id !== id));
    if (markedTrackId === id) setMarkedTrackId(null);
  }, [saveToHistory, markedTrackId]);

  const handleMerge = useCallback(() => {
    if (tracks.length < 2) return;
    saveToHistory();
    const merged = mergeTracks(tracks);
    setTracks([merged]);
    setMarkedTrackId(merged.id);
  }, [tracks, saveToHistory]);

  const handleReorder = useCallback((oldIndex: number, newIndex: number) => {
    setTracks(prev => arrayMove(prev, oldIndex, newIndex));
  }, []);

  const handleMeasureResult = useCallback((dist: number | null) => {
    setMeasureResult(dist);
  }, []);

  const markedTrack = tracks.find(t => t.id === markedTrackId);

  return (
    <div className="flex h-screen w-screen overflow-hidden bg-slate-100 font-sans text-slate-900">
      <Sidebar 
        tracks={tracks}
        markedTrackId={markedTrackId}
        onMarkTrack={setMarkedTrackId}
        onUpload={handleFileUpload}
        onToggleVisibility={toggleVisibility}
        onRemoveTrack={removeTrack}
        onMergeSelected={handleMerge}
        onUndo={handleUndo}
        canUndo={history.length > 0}
        onReorder={handleReorder}
        activeLayer={activeLayer}
        setActiveLayer={setActiveLayer}
        measureMode={measureMode}
        setMeasureMode={(mode) => {
          setMeasureMode(mode);
          if (!mode) setMeasureResult(null);
        }}
        measureResult={measureResult}
      />
      <main className="flex-1 flex flex-col relative overflow-hidden">
        <div className="flex-1 relative">
          <Map 
            tracks={tracks} 
            activeLayer={activeLayer}
            measureMode={measureMode}
            onMeasureResult={handleMeasureResult}
            markedTrackId={markedTrackId}
            onMarkTrack={setMarkedTrackId}
          />

          {measureMode && (
            <div className="absolute top-4 left-1/2 -translate-x-1/2 z-[1000] bg-blue-600 text-white px-6 py-2 rounded-full shadow-lg text-sm font-medium animate-bounce">
              Mess-Modus: Wähle zwei Punkte auf der Karte
            </div>
          )}
        </div>

        {markedTrack && (
          <div className="h-48 bg-white border-t border-slate-200 p-4 shadow-inner z-20">
            <ElevationProfile track={markedTrack} />
          </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useMemo } from 'react';
import { GPXTrack, GPXPoint } from '../types';
import { calculateDistance } from '../utils/gpxUtils';

interface ElevationProfileProps {
  track: GPXTrack;
}

const ElevationProfile: React.FC<ElevationProfileProps> = ({ track }) => {
  const profileData = useMemo(() => {
    if (!track.points || track.points.length === 0) return null;

    let totalDist = 0;
    const data: { dist: number; ele: number }[] = [];

    // Check if we even have elevation data
    const hasElevation = track.points.some(p => p.ele !== undefined);
    if (!hasElevation) return null;

    data.push({ dist: 0, ele: track.points[0].ele || 0 });

    for (let i = 1; i < track.points.length; i++) {
      totalDist += calculateDistance(track.points[i - 1], track.points[i]);
      data.push({ dist: totalDist, ele: track.points[i].ele || 0 });
    }

    const minEle = Math.min(...data.map(d => d.ele));
    const maxEle = Math.max(...data.map(d => d.ele));
    const distRange = totalDist;
    const eleRange = maxEle - minEle || 1;

    return { data, minEle, maxEle, distRange, eleRange };
  }, [track]);

  if (!profileData) {
    return (
      <div className="flex flex-col items-center justify-center h-full text-slate-400">
        <p className="text-sm font-medium">Keine Höhendaten für "{track.name}" verfügbar.</p>
      </div>
    );
  }

  const { data, minEle, maxEle, distRange, eleRange } = profileData;
  const padding = { top: 10, bottom: 20, left: 40, right: 10 };
  const width = 1000;
  const height = 150;

  const points = data.map(d => {
    const x = (d.dist / distRange) * (width - padding.left - padding.right) + padding.left;
    const y = height - padding.bottom - ((d.ele - minEle) / eleRange) * (height - padding.top - padding.bottom);
    return `${x},${y}`;
  }).join(' ');

  const areaPath = `M${padding.left},${height - padding.bottom} ${points} L${width - padding.right},${height - padding.bottom} Z`;

  return (
    <div className="h-full w-full flex flex-col">
      <div className="flex justify-between items-end mb-1 px-1">
        <h3 className="text-xs font-bold text-slate-500 uppercase tracking-wider">Höhenprofil: {track.name}</h3>
        <div className="flex gap-4 text-[10px] font-mono text-slate-400">
          <span>MIN: {minEle.toFixed(0)}m</span>
          <span>MAX: {maxEle.toFixed(0)}m</span>
          <span>STG: {(maxEle - minEle).toFixed(0)}m</span>
        </div>
      </div>
      <div className="flex-1 min-h-0 relative">
        <svg viewBox={`0 0 ${width} ${height}`} className="w-full h-full preserve-aspect-ratio-none overflow-visible">
          <defs>
            <linearGradient id="elevationGradient" x1="0" y1="0" x2="0" y2="1">
              <stop offset="0%" stopColor={track.color} stopOpacity="0.4" />
              <stop offset="100%" stopColor={track.color} stopOpacity="0" />
            </linearGradient>
          </defs>

          {/* Grid lines */}
          <line x1={padding.left} y1={padding.top} x2={padding.left} y2={height - padding.bottom} stroke="#e2e8f0" strokeWidth="1" />
          <line x1={padding.left} y1={height - padding.bottom} x2={width - padding.right} y2={height - padding.bottom} stroke="#e2e8f0" strokeWidth="1" />

          {/* Area under the line */}
          <path d={areaPath} fill="url(#elevationGradient)" />

          {/* Main line */}
          <polyline
            fill="none"
            stroke={track.color}
            strokeWidth="2"
            strokeLinejoin="round"
            points={points}
          />

          {/* Labels */}
          <text x={padding.left - 5} y={padding.top + 5} textAnchor="end" className="text-[10px] fill-slate-400 font-mono">{maxEle.toFixed(0)}m</text>
          <text x={padding.left - 5} y={height - padding.bottom} textAnchor="end" className="text-[10px] fill-slate-400 font-mono">{minEle.toFixed(0)}m</text>
          <text x={padding.left} y={height - 5} textAnchor="start" className="text-[10px] fill-slate-400 font-mono">0 km</text>
          <text x={width - padding.right} y={height - 5} textAnchor="end" className="text-[10px] fill-slate-400 font-mono">{distRange.toFixed(1)} km</text>
        </svg>
      </div>
    </div>
  );
};

export default ElevationProfile;

import React from 'react';
import { GPXTrack, MapLayer } from '../types';
import { Upload, Trash2, Combine, Eye, EyeOff, Ruler, Layers, GripVertical, Undo2 } from 'lucide-react';
import { 
  DndContext, 
  closestCenter, 
  KeyboardSensor, 
  PointerSensor, 
  useSensor, 
  useSensors,
  DragEndEvent 
} from '@dnd-kit/core';
import { 
  SortableContext, 
  sortableKeyboardCoordinates, 
  verticalListSortingStrategy,
  useSortable 
} from '@dnd-kit/sortable';
import { CSS } from '@dnd-kit/utilities';

interface TrackItemProps {
  track: GPXTrack;
  isMarked: boolean;
  onMark: (id: string) => void;
  onToggleVisibility: (id: string) => void;
  onRemoveTrack: (id: string) => void;
}

const SortableTrackItem: React.FC<TrackItemProps> = ({ track, isMarked, onMark, onToggleVisibility, onRemoveTrack }) => {
  const {
    attributes,
    listeners,
    setNodeRef,
    transform,
    transition,
    isDragging
  } = useSortable({ id: track.id });

  const style = {
    transform: CSS.Transform.toString(transform),
    transition,
    zIndex: isDragging ? 50 : 'auto',
  };

  return (
    <div 
      ref={setNodeRef} 
      style={style}
      onClick={() => onMark(track.id)}
      className={`group cursor-pointer bg-white border rounded-lg p-3 hover:shadow-md transition-all ${isDragging ? 'shadow-xl opacity-50 bg-slate-50' : ''} ${isMarked ? 'border-blue-500 ring-1 ring-blue-500 bg-blue-50/30' : 'border-slate-200'}`}
    >
      <div className="flex items-start gap-2">
        <div {...attributes} {...listeners} onClick={(e) => e.stopPropagation()} className="drag-handle p-1 mt-0.5 hover:bg-slate-100 rounded text-slate-400 shrink-0">
          <GripVertical className="w-4 h-4" />
        </div>

        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2 mb-0.5">
            <div className="w-3 h-3 rounded-full shrink-0 shadow-sm border border-black/10" style={{ backgroundColor: track.color }}></div>
            <span className={`text-sm truncate ${isMarked ? 'font-bold text-blue-900' : 'font-semibold text-slate-800'}`}>{track.name}</span>
          </div>

          <div className="text-[11px] text-slate-500 flex items-center gap-2 ml-5">
            <span className={`${isMarked ? 'bg-blue-100 text-blue-700' : 'bg-slate-100 text-slate-600'} px-1.5 py-0.5 rounded font-mono`}>{track.distance.toFixed(2)} km</span>
            <span className="text-slate-300">•</span>
            <span>{track.points.length} Punkte</span>
          </div>
        </div>

        <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity shrink-0">
          <button 
            onClick={(e) => { e.stopPropagation(); onToggleVisibility(track.id); }} 
            className="p-1.5 hover:bg-slate-100 rounded text-slate-500 transition-colors" 
            title="Sichtbarkeit umschalten"
          >
            {track.visible ? <Eye className="w-4 h-4" /> : <EyeOff className="w-4 h-4" />}
          </button>
          <button 
            onClick={(e) => { e.stopPropagation(); onRemoveTrack(track.id); }} 
            className="p-1.5 hover:bg-red-50 rounded text-red-500 transition-colors" 
            title="Track entfernen"
          >
            <Trash2 className="w-4 h-4" />
          </button>
        </div>
      </div>
    </div>
  );
};

interface SidebarProps {
  tracks: GPXTrack[];
  markedTrackId: string | null;
  onMarkTrack: (id: string) => void;
  onUpload: (e: React.ChangeEvent<HTMLInputElement>) => void;
  onToggleVisibility: (id: string) => void;
  onRemoveTrack: (id: string) => void;
  onMergeSelected: () => void;
  onUndo: () => void;
  canUndo: boolean;
  onReorder: (oldIndex: number, newIndex: number) => void;
  activeLayer: MapLayer;
  setActiveLayer: (layer: MapLayer) => void;
  measureMode: boolean;
  setMeasureMode: (mode: boolean) => void;
  measureResult: number | null;
}

const Sidebar: React.FC<SidebarProps> = ({ 
  tracks, 
  markedTrackId,
  onMarkTrack,
  onUpload, 
  onToggleVisibility, 
  onRemoveTrack, 
  onMergeSelected,
  onUndo,
  canUndo,
  onReorder,
  activeLayer,
  setActiveLayer,
  measureMode,
  setMeasureMode,
  measureResult
}) => {
  const sensors = useSensors(
    useSensor(PointerSensor),
    useSensor(KeyboardSensor, {
      coordinateGetter: sortableKeyboardCoordinates,
    })
  );

  const handleDragEnd = (event: DragEndEvent) => {
    const { active, over } = event;
    if (over && active.id !== over.id) {
      const oldIndex = tracks.findIndex(t => t.id === active.id);
      const newIndex = tracks.findIndex(t => t.id === over.id);
      onReorder(oldIndex, newIndex);
    }
  };

  return (
    <div className="w-80 h-full bg-white/95 backdrop-blur-md shadow-2xl flex flex-col z-30 border-r border-slate-200 overflow-hidden">
      <div className="p-6 bg-slate-900 text-white">
        <h1 className="text-xl font-bold flex items-center gap-2">
          <Layers className="w-6 h-6 text-blue-400" />
          GPX Route Master
        </h1>
        <p className="text-xs text-slate-400 mt-1 uppercase tracking-widest">OSM Pro Tools</p>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-6">
        <section>
          <label className="flex flex-col items-center justify-center w-full h-24 border-2 border-dashed border-slate-300 rounded-xl cursor-pointer hover:bg-slate-50 transition-colors">
            <div className="flex flex-col items-center justify-center pt-5 pb-6">
              <Upload className="w-8 h-8 text-slate-400 mb-2" />
              <p className="text-sm text-slate-500 font-medium">GPX Datei hochladen</p>
            </div>
            <input type="file" className="hidden" accept=".gpx" multiple onChange={onUpload} />
          </label>
        </section>

        <section className="space-y-3">
          <div className="flex justify-between items-center">
            <h2 className="text-xs font-bold text-slate-400 uppercase tracking-wider">Werkzeuge</h2>
            {canUndo && (
              <button 
                onClick={onUndo}
                className="flex items-center gap-1 text-[10px] text-blue-600 font-bold hover:bg-blue-100 bg-blue-50 px-2 py-1 rounded transition-colors"
              >
                <Undo2 className="w-3 h-3" /> RÜCKGÄNGIG
              </button>
            )}
          </div>
          <div className="grid grid-cols-2 gap-2">
            <button 
              onClick={() => setMeasureMode(!measureMode)}
              className={`flex items-center justify-center gap-2 p-3 rounded-lg text-sm font-semibold transition-all ${measureMode ? 'bg-blue-600 text-white shadow-lg shadow-blue-200' : 'bg-slate-100 text-slate-700 hover:bg-slate-200'}`}
            >
              <Ruler className="w-4 h-4" />
              Messen
            </button>
            <button 
              onClick={onMergeSelected}
              disabled={tracks.length < 2}
              className="flex items-center justify-center gap-2 p-3 rounded-lg text-sm font-semibold bg-slate-100 text-slate-700 hover:bg-slate-200 disabled:opacity-50 disabled:cursor-not-allowed transition-all"
            >
              <Combine className="w-4 h-4" />
              Verbinden
            </button>
          </div>
          {measureMode && (
            <div className="p-3 bg-blue-50 border border-blue-100 rounded-lg text-xs text-blue-800 font-medium animate-pulse">
              {measureResult 
                ? `Abstand: ${measureResult.toFixed(2)} km` 
                : "Klicke zwei Punkte auf der Karte an."}
            </div>
          )}
        </section>

        <section className="space-y-3">
          <h2 className="text-xs font-bold text-slate-400 uppercase tracking-wider">Kartentyp</h2>
          <div className="grid grid-cols-2 gap-1.5">
            {Object.values(MapLayer).map((layer) => (
              <button
                key={layer}
                onClick={() => setActiveLayer(layer)}
                className={`text-left px-2.5 py-1.5 rounded-md text-[11px] font-semibold transition-colors ${activeLayer === layer ? 'bg-blue-100 text-blue-700 border border-blue-200' : 'text-slate-600 hover:bg-slate-50 border border-transparent'}`}
              >
                {layer}
              </button>
            ))}
          </div>
        </section>

        <section className="space-y-3">
          <h2 className="text-xs font-bold text-slate-400 uppercase tracking-wider">Routen ({tracks.length})</h2>
          <div className="space-y-2 pb-6">
            {tracks.length === 0 && (
              <p className="text-xs text-slate-400 italic text-center py-8 bg-slate-50/50 rounded-xl border border-dashed border-slate-200">Noch keine Routen geladen.</p>
            )}
            <DndContext 
              sensors={sensors}
              collisionDetection={closestCenter}
              onDragEnd={handleDragEnd}
            >
              <SortableContext 
                items={tracks.map(t => t.id)}
                strategy={verticalListSortingStrategy}
              >
                <div className="space-y-2">
                  {tracks.map((track) => (
                    <SortableTrackItem 
                      key={track.id} 
                      track={track} 
                      isMarked={markedTrackId === track.id}
                      onMark={onMarkTrack}
                      onToggleVisibility={onToggleVisibility} 
                      onRemoveTrack={onRemoveTrack} 
                    />
                  ))}
