              </SortableContext>
            </DndContext>
          </div>
        </section>
      </div>

      <div className="p-4 border-t border-slate-200 bg-slate-50 text-[10px] text-slate-400 text-center font-medium">
        Reihenfolge bestimmt Verbindungssequenz
      </div>
    </div>
  );
