import React, { useEffect, useState } from 'react';
import { MapContainer, TileLayer, Polyline, useMapEvents, useMap, Marker, Popup } from 'react-leaflet';
import L from 'leaflet';
import { GPXTrack, MapLayer, MAP_LAYERS } from '../types';
import { calculateDistance } from '../utils/gpxUtils';

// Fix for default marker icons in Leaflet + React
// @ts-ignore
delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon-2x.png',
  iconUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon.png',
  shadowUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-shadow.png',
});

interface MapProps {
  tracks: GPXTrack[];
  activeLayer: MapLayer;
  measureMode: boolean;
  onMeasureResult: (dist: number | null) => void;
  markedTrackId: string | null;
  onMarkTrack: (id: string) => void;
}

const ZoomToTracks = ({ tracks }: { tracks: GPXTrack[] }) => {
  const map = useMap();
  useEffect(() => {
    const visibleTracks = tracks.filter(t => t.visible);
    if (visibleTracks.length > 0) {
      const bounds = L.latLngBounds(visibleTracks[0].points.map(p => [p.lat, p.lng]));
      visibleTracks.forEach(t => {
        t.points.forEach(p => bounds.extend([p.lat, p.lng]));
      });
      map.fitBounds(bounds, { padding: [50, 50] });
    }
  }, [tracks, map]);
  return null;
};

const MeasurementTool = ({ active, onResult }: { active: boolean, onResult: (d: number | null) => void }) => {
  const [points, setPoints] = useState<L.LatLng[]>([]);

  useMapEvents({
    click(e) {
      if (!active) return;

      const newPoints = [...points, e.latlng];
      if (newPoints.length > 2) {
        setPoints([e.latlng]);
        onResult(null);
      } else {
        setPoints(newPoints);
        if (newPoints.length === 2) {
          const d = calculateDistance(
            { lat: newPoints[0].lat, lng: newPoints[0].lng },
            { lat: newPoints[1].lat, lng: newPoints[1].lng }
          );
          onResult(d);
        }
      }
    },
  });

  if (!active || points.length === 0) return null;

  return (
    <>
      {points.map((p, i) => (
        <Marker key={i} position={p} icon={new L.DivIcon({
          className: 'custom-div-icon',
          html: `<div class="bg-blue-600 w-3 h-3 rounded-full border-2 border-white"></div>`,
          iconSize: [12, 12],
          iconAnchor: [6, 6]
        })} />
      ))}
      {points.length === 2 && (
        <Polyline positions={points} color="blue" dashArray="5, 10" />
      )}
    </>
  );
};

const Map: React.FC<MapProps> = ({ tracks, activeLayer, measureMode, onMeasureResult, markedTrackId, onMarkTrack }) => {
  const layer = MAP_LAYERS[activeLayer];

  return (
    <div className="w-full h-full relative">
      <MapContainer 
        center={[51.1657, 10.4515]} 
        zoom={6} 
        scrollWheelZoom={true}
        className="z-0"
      >
        <TileLayer
          attribution={layer.attribution}
          url={layer.url}
        />

        {tracks.filter(t => t.visible).map(track => {
          const isMarked = track.id === markedTrackId;
          return (
            <Polyline 
              key={track.id} 
              positions={track.points.map(p => [p.lat, p.lng])}
              color={track.color}
              weight={isMarked ? 8 : 4}
              opacity={isMarked ? 1.0 : 0.6}
              eventHandlers={{
                click: (e) => {
                  L.DomEvent.stopPropagation(e);
                  onMarkTrack(track.id);
                }
              }}
            >
              <Popup>
                  <div className="font-bold">{track.name}</div>
                  <div>Distanz: {track.distance.toFixed(2)} km</div>
                  <div>Punkte: {track.points.length}</div>
              </Popup>
            </Polyline>
          );
        })}

        <ZoomToTracks tracks={tracks} />
        <MeasurementTool active={measureMode} onResult={onMeasureResult} />
      </MapContainer>
    </div>
  );
};

export default Map;

import React, { useMemo, useState, useRef } from 'react';
import { GPXTrack } from '../types';
import { calculateDistance } from '../utils/gpxUtils';

interface ElevationProfileProps {
  track: GPXTrack;
}

interface HoverInfo {
  dist: number;
  ele: number;
  slope: number;
  x: number;
  y: number;
}

const ElevationProfile: React.FC<ElevationProfileProps> = ({ track }) => {
  const svgRef = useRef<SVGSVGElement>(null);
  const [hoverInfo, setHoverInfo] = useState<HoverInfo | null>(null);

  const profileData = useMemo(() => {
    if (!track.points || track.points.length === 0) return null;

    let totalDist = 0;
    const data: { dist: number; ele: number }[] = [];

    const hasElevation = track.points.some(p => p.ele !== undefined);
    if (!hasElevation) return null;

    data.push({ dist: 0, ele: track.points[0].ele || 0 });

    for (let i = 1; i < track.points.length; i++) {
      totalDist += calculateDistance(track.points[i - 1], track.points[i]);
      data.push({ dist: totalDist, ele: track.points[i].ele || 0 });
    }

    const minEle = Math.min(...data.map(d => d.ele));
    const maxEle = Math.max(...data.map(d => d.ele));
    const distRange = totalDist;
    const eleRange = maxEle - minEle || 1;

    return { data, minEle, maxEle, distRange, eleRange };
  }, [track]);

  const padding = { top: 20, bottom: 25, left: 10, right: 10 };
  const width = 1000;
  const height = 150;

  const handleMouseMove = (e: React.MouseEvent<SVGSVGElement>) => {
    if (!profileData || !svgRef.current) return;

    const svg = svgRef.current;
    const rect = svg.getBoundingClientRect();
    const mouseX = e.clientX - rect.left;

    // Convert screen X to SVG coordinate space
    const svgX = (mouseX / rect.width) * width;

    // Clamp to graph area
    const graphLeft = padding.left;
    const graphRight = width - padding.right;
    const clampedX = Math.max(graphLeft, Math.min(graphRight, svgX));

    // Map X to distance
    const distPercent = (clampedX - graphLeft) / (graphRight - graphLeft);
    const targetDist = distPercent * profileData.distRange;

    // Find closest point
    let closestIdx = 0;
    let minDiff = Infinity;
    for (let i = 0; i < profileData.data.length; i++) {
      const diff = Math.abs(profileData.data[i].dist - targetDist);
      if (diff < minDiff) {
        minDiff = diff;
        closestIdx = i;
      }
    }

    const point = profileData.data[closestIdx];

    // Calculate slope (steigung) based on surrounding points
    let slope = 0;
    const prev = profileData.data[Math.max(0, closestIdx - 2)];
    const next = profileData.data[Math.min(profileData.data.length - 1, closestIdx + 2)];
    const dDist = next.dist - prev.dist;
    if (dDist > 0) {
      // Slope in %: (Rise / Run) * 100
      slope = ((next.ele - prev.ele) / (dDist * 1000)) * 100;
    }

    const x = (point.dist / profileData.distRange) * (graphRight - graphLeft) + graphLeft;
    const y = height - padding.bottom - ((point.ele - profileData.minEle) / profileData.eleRange) * (height - padding.top - padding.bottom);

    setHoverInfo({
      dist: point.dist,
      ele: point.ele,
      slope,
      x,
      y
    });
  };

  if (!profileData) {
    return (
      <div className="flex flex-col items-center justify-center h-full text-slate-400">
        <p className="text-sm font-medium">Keine Höhendaten für "{track.name}" verfügbar.</p>
      </div>
    );
  }

  const { data, minEle, maxEle, distRange, eleRange } = profileData;
  const graphWidth = width - padding.left - padding.right;
  const graphHeight = height - padding.top - padding.bottom;

  const points = data.map(d => {
    const x = (d.dist / distRange) * graphWidth + padding.left;
    const y = height - padding.bottom - ((d.ele - minEle) / eleRange) * graphHeight;
    return `${x},${y}`;
  }).join(' ');

  const areaPath = `M${padding.left},${height - padding.bottom} ${points} L${width - padding.right},${height - padding.bottom} Z`;

  return (
    <div className="h-full w-full flex flex-col select-none">
      <div className="flex justify-between items-center mb-2 px-2">
        <div className="flex items-center gap-3">
          <div className="w-2 h-2 rounded-full" style={{ backgroundColor: track.color }}></div>
          <h3 className="text-xs font-bold text-slate-600 uppercase tracking-wider truncate max-w-[300px]">
            {track.name}
          </h3>
        </div>
        <div className="flex gap-4 text-[10px] font-bold font-mono text-slate-500 bg-slate-50 px-3 py-1 rounded-full border border-slate-100 shadow-sm">
          <span className="flex gap-1"><span className="text-slate-400">MIN:</span> {minEle.toFixed(0)}m</span>
          <span className="flex gap-1"><span className="text-slate-400">MAX:</span> {maxEle.toFixed(0)}m</span>
          <span className="flex gap-1"><span className="text-slate-400">DIFF:</span> {(maxEle - minEle).toFixed(0)}m</span>
          <span className="flex gap-1"><span className="text-slate-400">DIST:</span> {distRange.toFixed(1)}km</span>
        </div>
      </div>

      <div className="flex-1 min-h-0 relative">
        <svg 
          ref={svgRef}
          viewBox={`0 0 ${width} ${height}`} 
          className="w-full h-full overflow-visible"
          preserveAspectRatio="none"
          onMouseMove={handleMouseMove}
          onMouseLeave={() => setHoverInfo(null)}
        >
          <defs>
            <linearGradient id={`grad-${track.id}`} x1="0" y1="0" x2="0" y2="1">
              <stop offset="0%" stopColor={track.color} stopOpacity="0.4" />
              <stop offset="100%" stopColor={track.color} stopOpacity="0.05" />
            </linearGradient>
            <filter id="shadow">
              <feDropShadow dx="0" dy="1" stdDeviation="1" floodOpacity="0.2"/>
            </filter>
          </defs>

          {/* Y-Axis Grid lines */}
          <line x1={padding.left} y1={padding.top} x2={width - padding.right} y2={padding.top} stroke="#f1f5f9" strokeWidth="1" />
          <line x1={padding.left} y1={padding.top + graphHeight / 2} x2={width - padding.right} y2={padding.top + graphHeight / 2} stroke="#f8fafc" strokeWidth="1" />

          {/* Area under the line */}
          <path d={areaPath} fill={`url(#grad-${track.id})`} />

          {/* Main line */}
          <polyline
            fill="none"
            stroke={track.color}
            strokeWidth="2.5"
            strokeLinejoin="round"
            strokeLinecap="round"
            points={points}
          />

          {/* Distance Labels (X-Axis) */}
          {[0, 0.25, 0.5, 0.75, 1].map(p => {
            const x = padding.left + p * graphWidth;
            return (
              <g key={p}>
                <line x1={x} y1={height - padding.bottom} x2={x} y2={height - padding.bottom + 4} stroke="#cbd5e1" strokeWidth="1" />
                <text x={x} y={height - 8} textAnchor="middle" className="text-[9px] fill-slate-400 font-mono font-medium">
                  {(p * distRange).toFixed(1)}
                </text>
              </g>
            )
          })}
          <text x={width / 2} y={height - 2} textAnchor="middle" className="text-[8px] fill-slate-300 font-bold uppercase tracking-widest">Entfernung (km)</text>

          {/* Hover indicator */}
          {hoverInfo && (
            <g>
              <line 
                x1={hoverInfo.x} 
                y1={padding.top} 
                x2={hoverInfo.x} 
                y2={height - padding.bottom} 
                stroke="#64748b" 
                strokeWidth="1" 
                strokeDasharray="4 2" 
              />
              <circle 
                cx={hoverInfo.x} 
                cy={hoverInfo.y} 
                r="5" 
                fill="white" 
                stroke={track.color} 
                strokeWidth="2" 
                filter="url(#shadow)"
              />

              {/* Tooltip background */}
              <rect 
