import React, { useMemo, useState, useRef } from 'react';
import { GPXTrack } from '../types';
import { calculateDistance } from '../utils/gpxUtils';

interface ElevationProfileProps {
  track: GPXTrack;
}

interface HoverInfo {
  dist: number;
  ele: number;
  slope: number;
  x: number;
  y: number;
}

const ElevationProfile: React.FC<ElevationProfileProps> = ({ track }) => {
  const svgRef = useRef<SVGSVGElement>(null);
  const [hoverInfo, setHoverInfo] = useState<HoverInfo | null>(null);

  const profileData = useMemo(() => {
    if (!track.points || track.points.length === 0) return null;

    let totalDist = 0;
    const data: { dist: number; ele: number; slope: number }[] = [];

    const hasElevation = track.points.some(p => p.ele !== undefined);
    if (!hasElevation) return null;

    data.push({ dist: 0, ele: track.points[0].ele || 0, slope: 0 });

    let maxSlopeVal = 0;
    let maxSlopeIdx = 0;

    for (let i = 1; i < track.points.length; i++) {
      const distStep = calculateDistance(track.points[i - 1], track.points[i]);
      totalDist += distStep;
      const ele = track.points[i].ele || 0;

      let slope = 0;
      if (distStep > 0) {
        slope = ((ele - (track.points[i - 1].ele || 0)) / (distStep * 1000)) * 100;
      }

      data.push({ dist: totalDist, ele, slope });

      if (Math.abs(slope) > Math.abs(maxSlopeVal)) {
        maxSlopeVal = slope;
        maxSlopeIdx = i;
      }
    }

    const minEle = Math.min(...data.map(d => d.ele));
    const maxEle = Math.max(...data.map(d => d.ele));
    const distRange = totalDist;
    const eleRange = maxEle - minEle || 1;

    return { data, minEle, maxEle, distRange, eleRange, maxSlopeVal, maxSlopeIdx };
  }, [track]);

  const padding = { top: 20, bottom: 25, left: 10, right: 10 };
  const width = 1000;
  const height = 150;

  const handleMouseMove = (e: React.MouseEvent<SVGSVGElement>) => {
    if (!profileData || !svgRef.current) return;

    const svg = svgRef.current;
    const rect = svg.getBoundingClientRect();
    const mouseX = e.clientX - rect.left;

    const svgX = (mouseX / rect.width) * width;

    const graphLeft = padding.left;
    const graphRight = width - padding.right;
    const clampedX = Math.max(graphLeft, Math.min(graphRight, svgX));

    const distPercent = (clampedX - graphLeft) / (graphRight - graphLeft);
    const targetDist = distPercent * profileData.distRange;

    let closestIdx = 0;
    let minDiff = Infinity;
    for (let i = 0; i < profileData.data.length; i++) {
      const diff = Math.abs(profileData.data[i].dist - targetDist);
      if (diff < minDiff) {
        minDiff = diff;
        closestIdx = i;
      }
    }

    const point = profileData.data[closestIdx];
    const x = (point.dist / profileData.distRange) * (graphRight - graphLeft) + graphLeft;
    const y = height - padding.bottom - ((point.ele - profileData.minEle) / profileData.eleRange) * (height - padding.top - padding.bottom);

    setHoverInfo({
      dist: point.dist,
      ele: point.ele,
      slope: point.slope,
      x,
      y
    });
  };

  if (!profileData) {
    return (
      <div className="flex flex-col items-center justify-center h-full text-slate-400">
        <p className="text-sm font-medium">Keine Höhendaten für "{track.name}" verfügbar.</p>
      </div>
    );
  }

  const { data, minEle, maxEle, distRange, eleRange, maxSlopeVal, maxSlopeIdx } = profileData;
  const graphWidth = width - padding.left - padding.right;
  const graphHeight = height - padding.top - padding.bottom;

  const points = data.map(d => {
    const x = (d.dist / distRange) * graphWidth + padding.left;
    const y = height - padding.bottom - ((d.ele - minEle) / eleRange) * graphHeight;
    return `${x},${y}`;
  }).join(' ');

  const areaPath = `M${padding.left},${height - padding.bottom} ${points} L${width - padding.right},${height - padding.bottom} Z`;

  // Max Slope Point Coordinates
  const maxSlopePoint = data[maxSlopeIdx];
  const maxSlopeX = (maxSlopePoint.dist / distRange) * graphWidth + padding.left;
  const maxSlopeY = height - padding.bottom - ((maxSlopePoint.ele - minEle) / eleRange) * graphHeight;

  return (
    <div className="h-full w-full flex flex-col select-none">
      <div className="flex justify-between items-center mb-2 px-2">
        <div className="flex items-center gap-3">
          <div className="w-2 h-2 rounded-full" style={{ backgroundColor: track.color }}></div>
          <h3 className="text-xs font-bold text-slate-600 uppercase tracking-wider truncate max-w-[200px]">
            {track.name}
          </h3>
        </div>
        <div className="flex flex-wrap gap-x-4 gap-y-1 text-[10px] font-bold font-mono text-slate-500 bg-slate-50 px-3 py-1 rounded-full border border-slate-100 shadow-sm">
          <span className="flex gap-1"><span className="text-emerald-600">▲</span> {track.ascent.toFixed(0)}m</span>
          <span className="flex gap-1"><span className="text-rose-600">▼</span> {track.descent.toFixed(0)}m</span>
          <span className="flex gap-1"><span className="text-slate-400">MAX STG:</span> {track.maxSlope.toFixed(1)}%</span>
          <span className="flex gap-1"><span className="text-slate-400">MIN/MAX:</span> {minEle.toFixed(0)}/{maxEle.toFixed(0)}m</span>
        </div>
      </div>

      <div className="flex-1 min-h-0 relative">
        <svg 
          ref={svgRef}
          viewBox={`0 0 ${width} ${height}`} 
          className="w-full h-full overflow-visible"
          preserveAspectRatio="none"
          onMouseMove={handleMouseMove}
          onMouseLeave={() => setHoverInfo(null)}
        >
          <defs>
            <linearGradient id={`grad-${track.id}`} x1="0" y1="0" x2="0" y2="1">
              <stop offset="0%" stopColor={track.color} stopOpacity="0.4" />
              <stop offset="100%" stopColor={track.color} stopOpacity="0.05" />
            </linearGradient>
            <filter id="shadow">
              <feDropShadow dx="0" dy="1" stdDeviation="1" floodOpacity="0.2"/>
            </filter>
          </defs>

          <line x1={padding.left} y1={padding.top} x2={width - padding.right} y2={padding.top} stroke="#f1f5f9" strokeWidth="1" />
          <line x1={padding.left} y1={padding.top + graphHeight / 2} x2={width - padding.right} y2={padding.top + graphHeight / 2} stroke="#f8fafc" strokeWidth="1" />

          <path d={areaPath} fill={`url(#grad-${track.id})`} />

          <polyline
            fill="none"
            stroke={track.color}
            strokeWidth="2.5"
            strokeLinejoin="round"
            strokeLinecap="round"
            points={points}
          />

          {/* Marker for Max Slope */}
          <g>
            <circle 
              cx={maxSlopeX} 
              cy={maxSlopeY} 
              r="4" 
              fill="white" 
              stroke="#000" 
              strokeWidth="1.5" 
            />
            <text 
              x={maxSlopeX} 
              y={maxSlopeY - 8} 
              textAnchor="middle" 
              className="text-[8px] fill-slate-800 font-bold"
            >
              Max {maxSlopeVal.toFixed(1)}%
            </text>
          </g>

          {[0, 0.25, 0.5, 0.75, 1].map(p => {
            const x = padding.left + p * graphWidth;
            return (
              <g key={p}>
                <line x1={x} y1={height - padding.bottom} x2={x} y2={height - padding.bottom + 4} stroke="#cbd5e1" strokeWidth="1" />
                <text x={x} y={height - 8} textAnchor="middle" className="text-[9px] fill-slate-400 font-mono font-medium">
                  {(p * distRange).toFixed(1)}
                </text>
              </g>
            )
          })}
          <text x={width / 2} y={height - 2} textAnchor="middle" className="text-[8px] fill-slate-300 font-bold uppercase tracking-widest">Entfernung (km)</text>

          {hoverInfo && (
            <g>
              <line 
                x1={hoverInfo.x} 
                y1={padding.top} 
                x2={hoverInfo.x} 
                y2={height - padding.bottom} 
                stroke="#64748b" 
                strokeWidth="1" 
                strokeDasharray="4 2" 
              />
              <circle 
                cx={hoverInfo.x} 
                cy={hoverInfo.y} 
                r="5" 
                fill="white" 
                stroke={track.color} 
                strokeWidth="2" 
                filter="url(#shadow)"
              />

              <rect 
                x={hoverInfo.x + 10 > width - 100 ? hoverInfo.x - 110 : hoverInfo.x + 10} 
                y={hoverInfo.y - 45 < 5 ? hoverInfo.y + 15 : hoverInfo.y - 45} 
                width="100" 
                height="40" 
                rx="4" 
                fill="white" 
                stroke="#e2e8f0" 
                filter="url(#shadow)"
              />

              <text 
                x={hoverInfo.x + 10 > width - 100 ? hoverInfo.x - 105 : hoverInfo.x + 15} 
                y={hoverInfo.y - 45 < 5 ? hoverInfo.y + 30 : hoverInfo.y - 30} 
                className="text-[10px] font-bold fill-slate-700 font-mono"
              >
                {hoverInfo.ele.toFixed(0)}m
              </text>
              <text 
                x={hoverInfo.x + 10 > width - 100 ? hoverInfo.x - 105 : hoverInfo.x + 15} 
                y={hoverInfo.y - 45 < 5 ? hoverInfo.y + 45 : hoverInfo.y - 15} 
                className="text-[9px] fill-slate-500 font-mono"
              >
                {hoverInfo.dist.toFixed(2)}km | {hoverInfo.slope.toFixed(1)}%
              </text>
            </g>
          )}
        </svg>
      </div>
    </div>
  );
};

export default ElevationProfile;

import { GPXPoint, GPXTrack } from '../types';

/**
 * Basic Haversine distance calculation in kilometers
 */
export const calculateDistance = (p1: GPXPoint, p2: GPXPoint): number => {
  const R = 6371; // Earth's radius in km
  const dLat = (p2.lat - p1.lat) * Math.PI / 180;
  const dLng = (p2.lng - p1.lng) * Math.PI / 180;
  const a = 
    Math.sin(dLat / 2) * Math.sin(dLat / 2) +
    Math.cos(p1.lat * Math.PI / 180) * Math.cos(p2.lat * Math.PI / 180) * 
    Math.sin(dLng / 2) * Math.sin(dLng / 2);
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
  return R * c;
};

export const calculateElevationStats = (points: GPXPoint[]) => {
  let ascent = 0;
  let descent = 0;
  let maxSlope = 0; // Specifically tracking maximum positive incline
  let totalDist = 0;

  for (let i = 0; i < points.length - 1; i++) {
    const p1 = points[i];
    const p2 = points[i + 1];
    const distKm = calculateDistance(p1, p2);
    totalDist += distKm;

    if (p1.ele !== undefined && p2.ele !== undefined) {
      const diff = p2.ele - p1.ele;
      if (diff > 0) {
        ascent += diff;
        // Calculate positive slope for this segment
        if (distKm > 0) {
          const slope = (diff / (distKm * 1000)) * 100;
          if (slope > maxSlope) {
            maxSlope = slope;
          }
        }
      } else {
        descent += Math.abs(diff);
      }
    }
  }

  return { ascent, descent, maxSlope, totalDist };
};

export const parseGPX = (xmlString: string, fileName: string): GPXTrack | null => {
  try {
    const parser = new DOMParser();
    const xml = parser.parseFromString(xmlString, "text/xml");
    const trkpts = xml.querySelectorAll("trkpt");

    if (trkpts.length === 0) return null;

    const points: GPXPoint[] = Array.from(trkpts).map((pt) => {
      const lat = parseFloat(pt.getAttribute("lat") || "0");
      const lng = parseFloat(pt.getAttribute("lon") || "0");
      const eleNode = pt.querySelector("ele");
      const ele = eleNode ? parseFloat(eleNode.textContent || "0") : undefined;
      const timeStr = pt.querySelector("time")?.textContent;
      const time = timeStr ? new Date(timeStr) : undefined;
      return { lat, lng, ele, time };
    });

    const name = xml.querySelector("name")?.textContent || fileName || "Unbenannter Track";
    const { ascent, descent, maxSlope, totalDist } = calculateElevationStats(points);

    const randomColor = `#${Math.floor(Math.random() * 16777215).toString(16).padStart(6, '0')}`;

    return {
      id: crypto.randomUUID ? crypto.randomUUID() : `track-${Date.now()}-${Math.random()}`,
      name,
      points,
      color: randomColor,
      distance: totalDist,
      ascent,
      descent,
      maxSlope,
      visible: true
    };
  } catch (error) {
    console.error("Error parsing GPX:", error);
    return null;
  }
};

export const mergeTracks = (tracks: GPXTrack[]): GPXTrack => {
  const combinedPoints: GPXPoint[] = tracks.flatMap(t => t.points);
  const names = tracks.map(t => t.name).join(" → ");
  const { ascent, descent, maxSlope, totalDist } = calculateElevationStats(combinedPoints);

  return {
    id: crypto.randomUUID ? crypto.randomUUID() : `merged-${Date.now()}-${Math.random()}`,
    name: `Kombiniert: ${names.substring(0, 40)}${names.length > 40 ? '...' : ''}`,
    points: combinedPoints,
    color: "#ef4444",
    distance: totalDist,
    ascent,
    descent,
    maxSlope,
    visible: true
  };
};

import React, { useMemo, useState, useRef } from 'react';
import { GPXTrack } from '../types';
import { calculateDistance } from '../utils/gpxUtils';

interface ElevationProfileProps {
  track: GPXTrack;
}

interface HoverInfo {
  dist: number;
  ele: number;
  slope: number;
  x: number;
  y: number;
}

const ElevationProfile: React.FC<ElevationProfileProps> = ({ track }) => {
  const svgRef = useRef<SVGSVGElement>(null);
  const [hoverInfo, setHoverInfo] = useState<HoverInfo | null>(null);

  const profileData = useMemo(() => {
    if (!track.points || track.points.length === 0) return null;

    let totalDist = 0;
    const data: { dist: number; ele: number; slope: number }[] = [];

    const hasElevation = track.points.some(p => p.ele !== undefined);
    if (!hasElevation) return null;

    data.push({ dist: 0, ele: track.points[0].ele || 0, slope: 0 });

    let maxPosSlopeVal = 0;
    let maxPosSlopeIdx = 0;

    for (let i = 1; i < track.points.length; i++) {
      const distStep = calculateDistance(track.points[i - 1], track.points[i]);
      totalDist += distStep;
      const ele = track.points[i].ele || 0;

      let slope = 0;
      if (distStep > 0) {
        slope = ((ele - (track.points[i - 1].ele || 0)) / (distStep * 1000)) * 100;
      }

      data.push({ dist: totalDist, ele, slope });

      // We specifically look for the maximum positive slope here
      if (slope > maxPosSlopeVal) {
        maxPosSlopeVal = slope;
        maxPosSlopeIdx = i;
      }
    }

    const minEle = Math.min(...data.map(d => d.ele));
    const maxEle = Math.max(...data.map(d => d.ele));
    const distRange = totalDist;
    const eleRange = maxEle - minEle || 1;

    return { data, minEle, maxEle, distRange, eleRange, maxPosSlopeVal, maxPosSlopeIdx };
  }, [track]);

  const padding = { top: 25, bottom: 25, left: 10, right: 10 };
  const width = 1000;
  const height = 150;

  const handleMouseMove = (e: React.MouseEvent<SVGSVGElement>) => {
    if (!profileData || !svgRef.current) return;

    const svg = svgRef.current;
    const rect = svg.getBoundingClientRect();
    const mouseX = e.clientX - rect.left;

    const svgX = (mouseX / rect.width) * width;

    const graphLeft = padding.left;
    const graphRight = width - padding.right;
    const clampedX = Math.max(graphLeft, Math.min(graphRight, svgX));

    const distPercent = (clampedX - graphLeft) / (graphRight - graphLeft);
    const targetDist = distPercent * profileData.distRange;

    let closestIdx = 0;
    let minDiff = Infinity;
    for (let i = 0; i < profileData.data.length; i++) {
      const diff = Math.abs(profileData.data[i].dist - targetDist);
      if (diff < minDiff) {
        minDiff = diff;
        closestIdx = i;
      }
    }

    const point = profileData.data[closestIdx];
    const x = (point.dist / profileData.distRange) * (graphRight - graphLeft) + graphLeft;
    const y = height - padding.bottom - ((point.ele - profileData.minEle) / profileData.eleRange) * (height - padding.top - padding.bottom);

    setHoverInfo({
      dist: point.dist,
      ele: point.ele,
      slope: point.slope,
      x,
      y
    });
  };

  if (!profileData) {
    return (
      <div className="flex flex-col items-center justify-center h-full text-slate-400">
        <p className="text-sm font-medium">Keine Höhendaten für "{track.name}" verfügbar.</p>
      </div>
    );
  }

  const { data, minEle, maxEle, distRange, eleRange, maxPosSlopeVal, maxPosSlopeIdx } = profileData;
  const graphWidth = width - padding.left - padding.right;
  const graphHeight = height - padding.top - padding.bottom;

  const points = data.map(d => {
    const x = (d.dist / distRange) * graphWidth + padding.left;
    const y = height - padding.bottom - ((d.ele - minEle) / eleRange) * graphHeight;
    return `${x},${y}`;
  }).join(' ');

  const areaPath = `M${padding.left},${height - padding.bottom} ${points} L${width - padding.right},${height - padding.bottom} Z`;

  // Coordinates for marking the steepest uphill segment
  const maxSlopePoint = data[maxPosSlopeIdx];
  const maxSlopeX = (maxSlopePoint.dist / distRange) * graphWidth + padding.left;
  const maxSlopeY = height - padding.bottom - ((maxSlopePoint.ele - minEle) / eleRange) * graphHeight;

  return (
    <div className="h-full w-full flex flex-col select-none">
      <div className="flex justify-between items-center mb-2 px-2">
        <div className="flex items-center gap-3">
          <div className="w-2 h-2 rounded-full shadow-sm" style={{ backgroundColor: track.color }}></div>
          <h3 className="text-xs font-bold text-slate-600 uppercase tracking-wider truncate max-w-[200px]">
            {track.name}
          </h3>
        </div>
        <div className="flex flex-wrap gap-x-4 gap-y-1 text-[10px] font-bold font-mono text-slate-500 bg-slate-50 px-3 py-1 rounded-full border border-slate-100 shadow-sm">
          <span className="flex gap-1 items-center"><span className="text-emerald-600 text-[14px]">▲</span> {track.ascent.toFixed(0)}m</span>
          <span className="flex gap-1 items-center"><span className="text-rose-600 text-[14px]">▼</span> {track.descent.toFixed(0)}m</span>
          <span className="flex gap-1 items-center"><span className="text-slate-400">MAX STEIGUNG:</span> <span className="text-emerald-700">{track.maxSlope.toFixed(1)}%</span></span>
          <span className="flex gap-1 items-center"><span className="text-slate-400">MIN/MAX:</span> {minEle.toFixed(0)}/{maxEle.toFixed(0)}m</span>
        </div>
      </div>

      <div className="flex-1 min-h-0 relative">
        <svg 
          ref={svgRef}
          viewBox={`0 0 ${width} ${height}`} 
          className="w-full h-full overflow-visible"
          preserveAspectRatio="none"
          onMouseMove={handleMouseMove}
          onMouseLeave={() => setHoverInfo(null)}
        >
          <defs>
            <linearGradient id={`grad-${track.id}`} x1="0" y1="0" x2="0" y2="1">
              <stop offset="0%" stopColor={track.color} stopOpacity="0.4" />
              <stop offset="100%" stopColor={track.color} stopOpacity="0.05" />
            </linearGradient>
            <filter id="shadow">
              <feDropShadow dx="0" dy="1" stdDeviation="1" floodOpacity="0.2"/>
            </filter>
          </defs>

          {/* Horizontal Grid */}
          <line x1={padding.left} y1={padding.top} x2={width - padding.right} y2={padding.top} stroke="#f1f5f9" strokeWidth="1" />
          <line x1={padding.left} y1={padding.top + graphHeight / 2} x2={width - padding.right} y2={padding.top + graphHeight / 2} stroke="#f8fafc" strokeWidth="1" />

          {/* Filled Path */}
          <path d={areaPath} fill={`url(#grad-${track.id})`} />

          {/* Elevation Line */}
          <polyline
            fill="none"
            stroke={track.color}
            strokeWidth="2.5"
            strokeLinejoin="round"
            strokeLinecap="round"
            points={points}
          />

          {/* Special Marker for Max POSITIVE Slope */}
          {maxPosSlopeVal > 0 && (
            <g>
              <circle 
                cx={maxSlopeX} 
                cy={maxSlopeY} 
                r="4.5" 
                fill="#10b981" 
                stroke="white" 
                strokeWidth="1.5"
                className="animate-pulse"
                style={{ filter: 'drop-shadow(0px 0px 2px rgba(16,185,129,0.5))' }}
              />
              <text 
                x={maxSlopeX} 
                y={maxSlopeY - 10} 
                textAnchor="middle" 
                className="text-[9px] fill-emerald-700 font-bold font-mono"
              >
                Max Steigung: {maxPosSlopeVal.toFixed(1)}%
              </text>
            </g>
          )}

          {/* Distance Ticks */}
          {[0, 0.25, 0.5, 0.75, 1].map(p => {
            const x = padding.left + p * graphWidth;
            return (
              <g key={p}>
                <line x1={x} y1={height - padding.bottom} x2={x} y2={height - padding.bottom + 4} stroke="#cbd5e1" strokeWidth="1" />
                <text x={x} y={height - 8} textAnchor="middle" className="text-[9px] fill-slate-400 font-mono font-medium">
                  {(p * distRange).toFixed(1)}
                </text>
              </g>
            )
          })}
          <text x={width / 2} y={height - 2} textAnchor="middle" className="text-[8px] fill-slate-300 font-bold uppercase tracking-widest">Entfernung (km)</text>

          {/* Interaction Tooltip */}
          {hoverInfo && (
            <g>
              <line 
                x1={hoverInfo.x} 
                y1={padding.top} 
                x2={hoverInfo.x} 
                y2={height - padding.bottom} 
                stroke="#64748b" 
                strokeWidth="1" 
                strokeDasharray="4 2" 
              />
              <circle 
                cx={hoverInfo.x} 
                cy={hoverInfo.y} 
                r="5" 
                fill="white" 
                stroke={track.color} 
                strokeWidth="2" 
                filter="url(#shadow)"
              />

              <rect 
                x={hoverInfo.x + 10 > width - 110 ? hoverInfo.x - 120 : hoverInfo.x + 10} 
                y={hoverInfo.y - 45 < 5 ? hoverInfo.y + 15 : hoverInfo.y - 45} 
                width="110" 
                height="40" 
                rx="6" 
                fill="white" 
                stroke="#e2e8f0" 
                filter="url(#shadow)"
              />

              <text 
                x={hoverInfo.x + 10 > width - 110 ? hoverInfo.x - 115 : hoverInfo.x + 15} 
                y={hoverInfo.y - 45 < 5 ? hoverInfo.y + 30 : hoverInfo.y - 30} 
                className="text-[10px] font-bold fill-slate-700 font-mono"
              >
                Höhe: {hoverInfo.ele.toFixed(0)}m
              </text>
              <text 
                x={hoverInfo.x + 10 > width - 110 ? hoverInfo.x - 115 : hoverInfo.x + 15} 
                y={hoverInfo.y - 45 < 5 ? hoverInfo.y + 45 : hoverInfo.y - 15} 
                className="text-[9px] fill-slate-500 font-mono"
              >
                {hoverInfo.dist.toFixed(2)}km | {hoverInfo.slope.toFixed(1)}%
              </text>
            </g>
          )}
        </svg>
      </div>
    </div>
  );
};

export default ElevationProfile;
